    int alloc_size = size * 4;  // 整数溢出
    char *buffer = (char *)malloc(alloc_size);
    if (buffer == NULL) return;
    // 假设用户输入size为0x40000001，则alloc_size = 0x100000004 -> 截断为4
    // 实际复制数据可能远大于4字节
    memcpy(buffer, user_input, size * 4); // 堆溢出
}


