        printf("Too large!\n");
        return;
    }
    memcpy(buffer, data, copy_size);  // 复制
    printf("Copied %d bytes\n", copy_size);
}

int main(int argc, char *argv[]) {
    if (argc != 3) return 1;
    int size = atoi(argv[1]);
    vulnerable(size, argv[2]);
    return 0;
}

如果size = 0x7FFFFFFF（最大int），则size+10 = 0x80000009，在int中表示为负数（-2147483639），小于64，通过检查。但memcpy的第三个参数是size_t（无符号），会将负数解释为巨大的正数（0x80000009），导致复制大量数据到buffer，造成栈溢出。

